import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function functions(){
    const test = async () => {
        try{
            const date = await axios.get("/test");
            return date;
        } catch(err){
            console.error(err.response);
        }
    }

    const navs = useNavigate();

    return {test, navs};
}
